  4	import { useGetClusterDetails } from '@odf/core/redux/utils';
  5	import { K8sResourceObj } from '@odf/core/types';
  6	import {
  7	  Breakdown,
  8	  DataConsumption,
  9	  Metrics,
 10	  ServiceType,
 11	} from '@odf/ocs/constants';
 12	import { DATA_CONSUMPTION_QUERIES } from '@odf/ocs/queries';
 13	import { getRangeVectorStats } from '@odf/shared/charts';
 14	import { OCS_OPERATOR } from '@odf/shared/constants';
 15	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
 16	import {
 17	  useCustomPrometheusPoll,
 18	  usePrometheusBasePath,
 19	} from '@odf/shared/hooks/custom-prometheus-poll';
 20	import { ClusterServiceVersionModel } from '@odf/shared/models';
 21	import { getName } from '@odf/shared/selectors';
 22	import { ClusterServiceVersionKind } from '@odf/shared/types';
 23	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 24	import { DataPoint } from '@odf/shared/utils';
 25	import { referenceForModel } from '@odf/shared/utils';
 26	import { PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
 27	import * as _ from 'lodash-es';
 28	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 29	import { DataConsumptionDropdown } from './data-consumption-card-dropdown';
 30	import DataConsumptionGraph from './data-consumption-graph';
 31	import PerformanceGraph from './performance-graph';
 32	import './data-consumption-card.scss';
 33	
 34	const timeSpan = {
 35	  [ServiceType.RGW]: 60 * 60 * 1000,
 36	  [ServiceType.MCG]: null,
 37	};
 38	
 39	const csvResource: K8sResourceObj = (ns) => ({
 40	  isList: true,
 41	  namespace: ns,
 42	  kind: referenceForModel(ClusterServiceVersionModel),
 43	});
 44	
 45	type ServiceTypeProps = {
 46	  queries: string[];
 47	  breakdownBy?: Breakdown;
 48	  metric: Metrics;
 49	};
 50	
 51	type Response = (PrometheusResponse | DataPoint<Date>[])[];
 52	
 53	const MCGCommonComponent: React.FC<ServiceTypeProps> = ({
 54	  queries,
 55	  breakdownBy,
 56	  metric,
 57	}) => {
 58	  const [queryA, queryAError, queryALoading] = useCustomPrometheusPoll({
 59	    query: queries?.[0],
 60	    endpoint: 'api/v1/query' as any,
 61	    basePath: usePrometheusBasePath(),
 62	  });
 63	  const [queryB, queryBError, queryBLoading] = useCustomPrometheusPoll({
 64	    query: queries?.[1],
 65	    endpoint: 'api/v1/query' as any,
 66	    basePath: usePrometheusBasePath(),
 67	  });
 68	  const [queryC, queryCError, queryCLoading] = useCustomPrometheusPoll({
 69	    query: queries?.[2],
 70	    endpoint: 'api/v1/query' as any,
 71	    basePath: usePrometheusBasePath(),
 72	  });
 73	  const [queryD, queryDError, queryDLoading] = useCustomPrometheusPoll({
 74	    query: queries?.[3],
 75	    endpoint: 'api/v1/query' as any,
 76	    basePath: usePrometheusBasePath(),
 77	  });
 78	
 79	  const loading =
 80	    queryALoading || queryBLoading || queryCLoading || queryDLoading;
 81	  const error =
 82	    !!queryAError || !!queryBError || !!queryCError || !!queryDError;
 83	  const data = !!queryA && !!queryB && !!queryC && !!queryD;
 84	  const response: Response = React.useMemo(() => {
 85	    return !loading && !error && data ? [queryA, queryB, queryC, queryD] : [];
 86	  }, [queryA, queryB, queryC, queryD, loading, error, data]);
 87	
 88	  return (
 89	    <DataConsumptionGraph
 90	      prometheusResponse={response as PrometheusResponse[]}
 91	      loading={loading}
 92	      loadError={error}
 93	      breakdownBy={breakdownBy}
 94	      metric={metric}
 95	    />
 96	  );
 97	};
 98	
 99	const AccountsLogical: React.FC<ServiceTypeProps> = ({
100	  queries,
101	  breakdownBy,
102	  metric,
103	}) => {
104	  const [usage, usageError, usageLoading] = useCustomPrometheusPoll({
105	    query: queries?.[0],
106	    endpoint: 'api/v1/query' as any,
107	    basePath: usePrometheusBasePath(),
108	  });
109	  const [totalUsage, totalUsageError, totalUsageLoading] =
110	    useCustomPrometheusPoll({
111	      query: queries?.[1],
112	      endpoint: 'api/v1/query' as any,
113	      basePath: usePrometheusBasePath(),
114	    });
115	
116	  const loading = usageLoading || totalUsageLoading;
117	  const error = !!usageError || !!totalUsageError;
118	  const data = !!usage && !!totalUsage;
119	  const response: Response = React.useMemo(() => {
120	    return !loading && !error && data ? [usage, totalUsage] : [];
121	  }, [usage, totalUsage, loading, error, data]);
122	
123	  return (
124	    <DataConsumptionGraph
125	      prometheusResponse={response as PrometheusResponse[]}
126	      loading={loading}
127	      loadError={error}
128	      breakdownBy={breakdownBy}
129	      metric={metric}
130	    />
131	  );
132	};
133	
134	const ProvidersEgress: React.FC<ServiceTypeProps> = ({
135	  queries,
136	  breakdownBy,
137	  metric,
138	}) => {
139	  const [egress, egressError, egressLoading] = useCustomPrometheusPoll({
140	    query: queries?.[0],
141	    endpoint: 'api/v1/query' as any,
142	    basePath: usePrometheusBasePath(),
143	  });
144	
145	  const response: Response = React.useMemo(() => {
146	    return !egressLoading && !egressError && egress ? [egress] : [];
147	  }, [egress, egressError, egressLoading]);
148	
149	  return (
150	    <DataConsumptionGraph
151	      prometheusResponse={response as PrometheusResponse[]}
152	      loading={egressLoading}
153	      loadError={egressError}
154	      breakdownBy={breakdownBy}
155	      metric={metric}
156	    />
157	  );
158	};
159	
160	const MCGBreakdownMetricMap = (queries: string[]) => {
161	  return {
162	    [Breakdown.ACCOUNTS]: {
163	      [Metrics.IOPS]: (
164	        <MCGCommonComponent
165	          queries={queries}
166	          metric={Metrics.IOPS}
167	          breakdownBy={Breakdown.ACCOUNTS}
168	        />
169	      ),
170	      [Metrics.LOGICAL]: (
171	        <AccountsLogical
172	          queries={queries}
173	          metric={Metrics.LOGICAL}
174	          breakdownBy={Breakdown.ACCOUNTS}
175	        />
176	      ),
177	    },
178	    [Breakdown.PROVIDERS]: {
179	      [Metrics.IOPS]: (
180	        <MCGCommonComponent
181	          queries={queries}
182	          metric={Metrics.IOPS}
183	          breakdownBy={Breakdown.PROVIDERS}
184	        />
185	      ),
186	      [Metrics.PHY_VS_LOG]: (
187	        <MCGCommonComponent
188	          queries={queries}
189	          metric={Metrics.PHY_VS_LOG}
190	          breakdownBy={Breakdown.PROVIDERS}
191	        />
192	      ),
193	      [Metrics.EGRESS]: (
194	        <ProvidersEgress
195	          queries={queries}
196	          metric={Metrics.EGRESS}
197	          breakdownBy={Breakdown.PROVIDERS}
198	        />
199	      ),
200	    },
201	  };
202	};
203	
204	const ServiceTypeRGW: React.FC<ServiceTypeProps> = ({ queries, metric }) => {
205	  const [get, getError, getLoading] = useCustomPrometheusPoll({
206	    query: queries?.[0],
207	    endpoint: 'api/v1/query_range' as any,
208	    timespan: timeSpan[ServiceType.RGW],
209	    basePath: usePrometheusBasePath(),
210	  });
211	  const [put, putError, putLoading] = useCustomPrometheusPoll({
212	    query: queries?.[1],
213	    endpoint: 'api/v1/query_range' as any,
214	    timespan: timeSpan[ServiceType.RGW],
215	    basePath: usePrometheusBasePath(),
216	  });
217	
218	  const loading = getLoading || putLoading;
219	  const error = !!getError || !!putError;
220	  const data = !!get && !!put;
221	  const response: DataPoint<Date>[][] = React.useMemo(() => {
222	    return !loading && !error && data
223	      ? [...getRangeVectorStats(get), ...getRangeVectorStats(put)]
224	      : [];
225	  }, [get, put, loading, error, data]);
226	
227	  return (
228	    <PerformanceGraph
229	      loading={loading}
230	      loadError={error}
231	      dataPoints={response}
232	      metricType={metric}
233	    />
234	  );
235	};
236	
237	const DataConsumptionCard: React.FC = () => {
238	  const { t } = useCustomTranslation();
239	  const [breakdownBy, setBreakdownBy] = React.useState(Breakdown.PROVIDERS);
240	  const [metric, setMetric] = React.useState(Metrics.IOPS);
241	  const [serviceType, setServiceType] = React.useState(ServiceType.MCG);
242	
243	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
244	  const { systemFlags } = useODFSystemFlagsSelector();
245	  const RGW = systemFlags[clusterNs]?.isRGWAvailable;
246	  const MCG = systemFlags[clusterNs]?.isNoobaaAvailable;
247	  const managedByOCS = systemFlags[clusterNs]?.ocsClusterName;
248	
249	  const [csvList, csvLoaded, csvLoadError] =
250	    useSafeK8sWatchResource<ClusterServiceVersionKind[]>(csvResource);
251	  const isOCS45 =
252	    csvLoaded &&
253	    !csvLoadError &&
254	    csvList?.find((obj) => _.startsWith(getName(obj), `${OCS_OPERATOR}.v4.5`));
255	
256	  React.useEffect(() => {
257	    if (RGW && !MCG) {
258	      setServiceType(ServiceType.RGW);
259	      setMetric(DataConsumption.defaultMetrics[ServiceType.RGW]);
260	      setBreakdownBy(null);
261	    }
262	  }, [RGW, MCG]);
263	
264	  const queries: string[] = React.useMemo(() => {
265	    return serviceType === ServiceType.MCG
266	      ? Object.values(
267	          DATA_CONSUMPTION_QUERIES[ServiceType.MCG][breakdownBy][metric] ??
268	            DATA_CONSUMPTION_QUERIES[ServiceType.MCG][breakdownBy][Metrics.IOPS]
269	        )
270	      : Object.values(
271	          DATA_CONSUMPTION_QUERIES[ServiceType.RGW](managedByOCS)[metric] ??
272	            DATA_CONSUMPTION_QUERIES[ServiceType.MCG][Metrics.BANDWIDTH]
273	        );
274	  }, [breakdownBy, metric, serviceType, managedByOCS]);
275	
276	  return (
277	    <Card>
278	      <CardHeader>
279	        <div className="pf-v6-u-display-flex pf-v6-u-justify-content-space-between">
280	          <CardTitle>
281	            {t('Performance')}
282	            <FieldLevelHelp>
283	              {t(
284	                'Shows an overview of the data consumption per provider or account collected from the day of the entity creation.'
285	              )}
286	            </FieldLevelHelp>
287	          </CardTitle>
288	          <DataConsumptionDropdown
289	            selectedService={serviceType}
290	            setSelectedService={setServiceType}
291	            selectedBreakdown={breakdownBy}
292	            setSelectedBreakdown={setBreakdownBy}
293	            selectedMetric={metric}
294	            setSelectedMetric={setMetric}
295	            isRgwSupported={RGW && !isOCS45}
296	            isMcgSupported={MCG}
297	          />
298	        </div>
299	      </CardHeader>
300	      <CardBody>
301	        {serviceType === ServiceType.MCG &&
302	          MCGBreakdownMetricMap(queries)[breakdownBy][metric]}
303	        {serviceType === ServiceType.RGW && (
304	          <ServiceTypeRGW queries={queries} metric={metric} />
305	        )}
306	      </CardBody>
307	    </Card>
308	  );
309	};
310	
311	export default DataConsumptionCard;

